// Email and Name Formatter тАФ string methods in action

const rawName  = "  ananya krishnan  ";   // messy input
const rawEmail = "Ananya.Krishnan@Example.COM";

// Clean up the name
const trimmedName  = rawName.trim();            // remove spaces
const formattedName = trimmedName              // chain methods
    .split(" ")                                 // split into words
    .map(w => w[0].toUpperCase() + w.slice(1)) // capitalise each
    .join(" ");                                 // rejoin

// Normalise email
const cleanEmail = rawEmail.toLowerCase();

// Extract username (before @)
const atIndex  = cleanEmail.indexOf("@");
const username = cleanEmail.slice(0, atIndex);

// Validate email has @ and .
const isValid  = cleanEmail.includes("@") && cleanEmail.includes(".");

console.log(`Name     : ${formattedName}`);
console.log(`Email    : ${cleanEmail}`);
console.log(`Username : ${username}`);
console.log(`Valid    : ${isValid}`);
console.log(`Length   : ${cleanEmail.length} characters`);

