// Type Conversion Showcase

// --- Explicit number conversion ---
const ageStr    = "25";
const ageNum    = Number(ageStr);     // 25 as number
const priceStr  = "1299.99";
const priceNum  = parseFloat(priceStr); // 1299.99
const pageStr   = "42 pages";
const pageNum   = parseInt(pageStr);  // 42 тАФ stops at first non-digit

console.log(ageNum   + 5);   // 30 (numeric addition)
console.log(ageStr   + 5);   // "255" (string concat тАФ coercion trap)
console.log(priceNum.toFixed(2)); // "1299.99"
console.log(pageNum);         // 42

// --- Falsy check ---
const values = [0, "", null, undefined, "hello", 42, false];
console.log("\n--- Falsy / Truthy ---");
values.forEach(v => {
    console.log(`${String(v).padEnd(10)} тЖТ ${Boolean(v)}`);
});

// --- Strict vs loose equality ---
console.log("\n--- Equality ---");
console.log(0 == false);   // true  (loose)
console.log(0 === false);  // false (strict тАФ different types)
console.log("5" == 5);     // true  (loose)
console.log("5" === 5);    // false (strict)

